<template>
  <div>
    <button type="button" @click="button1()">跳转管理界面</button>

    <button type="button" @click="button2()">绑定户号</button>

    <button type="button" @click="button3()">获取已绑定的户号</button>
  </div>
</template>

<script>
export default {
  name: "accountBinding", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    button1() {
      mam.navigator.accountsys.dumpToManager("11112460", null, null);
    },

    button2() {
      mam.navigator.accountsys.ModOrAddAccount(
        "11112460",
        "321",
        "holle2",
        "yes",
        null,
        null
      );
    },

    button3() {
      mam.navigator.accountsys.getAppAccountList("11112460", this.succ_result, null);
    },

    succ_result(obj) {
      alert("------------" + obj);
    },
  },
};
</script>
